//! Integration tests for fatxlib.
//!
//! These tests use file-backed FATX/XTAF images generated by fatx-mkimage.
//! No hardware required — all tests use temporary image files.

mod common;

use std::cell::RefCell;
use std::io::{Cursor, Read, Seek, SeekFrom, Write};
use std::rc::Rc;
use std::thread::sleep;
use std::time::Duration;

use fatxlib::error::FatxError;
use fatxlib::types::*;
use fatxlib::volume::FatxVolume;

#[derive(Default)]
struct FailingWriteState {
    fail_on_write: Option<usize>,
    writes_seen: usize,
}

struct FailingWriteCursor {
    inner: Cursor<Vec<u8>>,
    state: Rc<RefCell<FailingWriteState>>,
}

impl Read for FailingWriteCursor {
    fn read(&mut self, buf: &mut [u8]) -> std::io::Result<usize> {
        self.inner.read(buf)
    }
}

impl Seek for FailingWriteCursor {
    fn seek(&mut self, pos: SeekFrom) -> std::io::Result<u64> {
        self.inner.seek(pos)
    }
}

impl Write for FailingWriteCursor {
    fn write(&mut self, buf: &[u8]) -> std::io::Result<usize> {
        let mut state = self.state.borrow_mut();
        state.writes_seen += 1;
        if state.fail_on_write == Some(state.writes_seen) {
            return Err(std::io::Error::other("injected write failure"));
        }
        self.inner.write(buf)
    }

    fn flush(&mut self) -> std::io::Result<()> {
        self.inner.flush()
    }
}

