    let (_tmp, mut vol) = common::create_fatx_image(4);

    vol.create_directory("/a").expect("mkdir a");
    vol.create_directory("/a/b").expect("mkdir a/b");
    vol.create_directory("/a/b/c").expect("mkdir a/b/c");

